#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    Draft,
    Review,
    Approved,
    Rejected,
    Published,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Publish,
    Archive,
    Restore,
}

pub fn apply_events(events: &[Event]) -> State {
    let mut state = State::Draft;

    for event in events {
        state = match (state, *event) {
            (State::Draft, Event::Submit) => State::Review,
            (State::Review, Event::Approve) => State::Approved,
            (State::Review, Event::Reject) => State::Rejected,
            (State::Rejected, Event::Revise) => State::Draft,
            (State::Approved, Event::Publish) => State::Published,
            (State::Published, Event::Archive) => State::Archived,
            (State::Archived, Event::Restore) => State::Draft,
            (_, Event::Archive) => State::Archived,
            (_, Event::Restore) => State::Draft,
            (_, _) => state,
        };
    }

    state
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, State};

    #[test]
    fn happy_path_reaches_published() {
        let events = [Event::Submit, Event::Approve, Event::Publish];
        assert_eq!(apply_events(&events), State::Published);
    }

    #[test]
    fn reject_requires_revision_before_resubmit() {
        let events = [Event::Submit, Event::Reject, Event::Submit, Event::Approve];
        assert_eq!(apply_events(&events), State::Rejected);
    }

    #[test]
    fn restore_only_works_from_archived() {
        let events = [Event::Submit, Event::Restore, Event::Approve, Event::Publish];
        assert_eq!(apply_events(&events), State::Published);
    }

    #[test]
    fn archive_only_works_from_published() {
        let events = [Event::Submit, Event::Archive, Event::Approve, Event::Publish];
        assert_eq!(apply_events(&events), State::Review);
    }

    #[test]
    fn archived_item_can_restart_flow() {
        let events = [
            Event::Submit,
            Event::Approve,
            Event::Publish,
            Event::Archive,
            Event::Restore,
            Event::Submit,
            Event::Approve,
        ];
        assert_eq!(apply_events(&events), State::Approved);
    }

    #[test]
    fn invalid_events_do_not_change_state() {
        let events = [Event::Approve, Event::Publish, Event::Archive];
        assert_eq!(apply_events(&events), State::Draft);
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Welcome,
    PasswordReset,
    Receipt,
    Alert { critical: bool },
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Channel {
    Email,
    Sms,
    Push,
}

pub fn should_send(event: Event, channel: Channel, opted_in: bool) -> bool {
    match event {
        Event::Welcome => match channel {
            Channel::Email => true,
            Channel::Sms => false,
            Channel::Push => false,
        },
        Event::PasswordReset => match channel {
            Channel::Email | Channel::Sms => true,
            Channel::Push => false,
        },
        Event::Receipt => match channel {
            Channel::Email => true,
            Channel::Sms | Channel::Push => false,
        },
        Event::Alert { critical } => match channel {
            Channel::Email => true,
            Channel::Sms => critical,
            Channel::Push => critical,
        },
    } && opted_in
}

#[cfg(test)]
mod tests {
    use super::{should_send, Channel, Event};

    #[test]
    fn welcome_only_uses_email_when_opted_in() {
        assert!(should_send(Event::Welcome, Channel::Email, true));
        assert!(!should_send(Event::Welcome, Channel::Sms, true));
        assert!(!should_send(Event::Welcome, Channel::Push, true));
        assert!(!should_send(Event::Welcome, Channel::Email, false));
    }

    #[test]
    fn password_reset_can_use_push_and_sms() {
        assert!(should_send(Event::PasswordReset, Channel::Email, true));
        assert!(should_send(Event::PasswordReset, Channel::Sms, true));
        assert!(should_send(Event::PasswordReset, Channel::Push, true));
    }

    #[test]
    fn receipts_are_email_only() {
        assert!(should_send(Event::Receipt, Channel::Email, true));
        assert!(!should_send(Event::Receipt, Channel::Sms, true));
        assert!(!should_send(Event::Receipt, Channel::Push, true));
    }

    #[test]
    fn only_critical_alerts_use_sms_or_push() {
        assert!(should_send(Event::Alert { critical: true }, Channel::Email, true));
        assert!(should_send(Event::Alert { critical: true }, Channel::Sms, true));
        assert!(should_send(Event::Alert { critical: true }, Channel::Push, true));
        assert!(should_send(Event::Alert { critical: false }, Channel::Email, true));
        assert!(!should_send(Event::Alert { critical: false }, Channel::Sms, true));
        assert!(!should_send(Event::Alert { critical: false }, Channel::Push, true));
    }

    #[test]
    fn opt_out_blocks_all_channels() {
        assert!(!should_send(Event::PasswordReset, Channel::Push, false));
        assert!(!should_send(Event::Alert { critical: true }, Channel::Sms, false));
    }
}

