use std::collections::{BTreeMap, BTreeSet};

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Order {
    pub region: &'static str,
    pub month: &'static str,
    pub customer_id: u32,
    pub amount_cents: u32,
    pub cancelled: bool,
}

pub fn monthly_region_report(orders: &[Order]) -> Vec<String> {
    let mut grouped: BTreeMap<(&str, &str), (u32, BTreeSet<u32>, u32)> = BTreeMap::new();

    for order in orders {
        let entry = grouped
            .entry((order.month, order.region))
            .or_insert((0, BTreeSet::new(), 0));
        entry.0 += order.amount_cents;
        entry.1.insert(order.customer_id);
        entry.2 += 1;
    }

    let mut rows: Vec<_> = grouped
        .into_iter()
        .map(|((month, region), (total, customers, orders))| {
            (month, region, total, customers.len(), orders)
        })
        .collect();

    rows.sort_by(|a, b| a.1.cmp(b.1).then(a.0.cmp(b.0)));

    rows.into_iter()
        .map(|(month, region, total, customers, orders)| {
            format!(
                "{} {} total=${:.2} customers={} orders={}",
                month,
                region,
                total as f64 / 100.0,
                customers,
                orders
            )
        })
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

