                cancelled: true,
            },
            Order {
                region: "east",
                month: "2024-01",
                customer_id: 8,
                amount_cents: 500,
                cancelled: false,
            },
            Order {
                region: "east",
                month: "2024-02",
                customer_id: 8,
                amount_cents: 200,
                cancelled: false,
            },
            Order {
                region: "east",
                month: "2024-02",
                customer_id: 9,
                amount_cents: 900,
                cancelled: false,
            },
            Order {
                region: "north",
                month: "2024-01",
                customer_id: 1,
                amount_cents: 1000,
                cancelled: true,
            },
        ]
    }

    #[test]
    fn reports_grouped_totals_with_unique_customers() {
        let report = monthly_region_report(&sample_orders());
        assert_eq!(
            report,
            vec![
                "2024-01 east total=$5.00 customers=1 orders=1",
                "2024-02 east total=$11.00 customers=2 orders=2",
                "2024-01 west total=$15.00 customers=1 orders=2",
            ]
        );
    }

    #[test]
    fn omits_groups_with_only_cancelled_orders() {
        let report = monthly_region_report(&sample_orders());
        assert!(!report.iter().any(|line| line.contains("north")));
    }

    #[test]
    fn sorts_by_month_then_region() {
        let report = monthly_region_report(&sample_orders());
        let months_regions: Vec<_> = report
            .iter()
            .map(|line| {
                let mut parts = line.split_whitespace();
                let month = parts.next().unwrap();
                let region = parts.next().unwrap();
                format!("{} {}", month, region)
            })
            .collect();
        assert_eq!(
            months_regions,
            vec!["2024-01 east", "2024-01 west", "2024-02 east"]
        );
    }
}

