#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    StartWork,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Open;

    for event in events {
        status = match (status, event) {
            (Status::Open, Event::StartWork) => Status::InProgress,
            (Status::Open, Event::Resolve) => Status::Resolved,
            (Status::InProgress, Event::Resolve) => Status::Resolved,
            (Status::Resolved, Event::Close) => Status::Closed,
            (Status::Closed, Event::Reopen) => Status::Open,
            (Status::Resolved, Event::Reopen) => Status::Open,
            _ => status,
        };
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn close_requires_resolved_first() {
        assert_eq!(apply_events(&[Event::Close]), Status::Open);
        assert_eq!(
            apply_events(&[Event::StartWork, Event::Close]),
            Status::InProgress
        );
    }

    #[test]
    fn reopening_closed_ticket_goes_back_to_open() {
        assert_eq!(
            apply_events(&[
                Event::StartWork,
                Event::Resolve,
                Event::Close,
                Event::Reopen,
            ]),
            Status::Open
        );
    }

    #[test]
    fn reopening_resolved_ticket_returns_to_in_progress() {
        assert_eq!(
            apply_events(&[Event::StartWork, Event::Resolve, Event::Reopen]),
            Status::InProgress
        );
    }

    #[test]
    fn repeated_invalid_events_do_not_change_state() {
        assert_eq!(
            apply_events(&[
                Event::StartWork,
                Event::StartWork,
                Event::Resolve,
                Event::Resolve,
                Event::Reopen,
                Event::Close,
            ]),
            Status::Closed
        );
    }
}

pub fn selected_lengths(input: &str) -> Vec<usize> {
    input
        .lines()
        .flat_map(|line| line.split(','))
        .map(|part| part.trim())
        .filter(|part| !part.starts_with('#'))
        .map(|part| part.len())
        .collect()
}

#[cfg(test)]
mod tests {
    use super::selected_lengths;

    #[test]
    fn skips_empty_tokens_and_comment_lines() {
        let input = "apple, ,pear\n#ignore,this\n fig , kiwi ,,";
        assert_eq!(selected_lengths(input), vec![5, 4, 3, 4]);
    }

    #[test]
    fn ignores_inline_comment_tokens_only() {
        let input = "red,#skip,blue\n, green , #also_skip ,yellow";
        assert_eq!(selected_lengths(input), vec![3, 4, 5, 6]);
    }
}

