use std::cmp::Reverse;

#[derive(Clone, Debug)]
struct Team {
    name: &'static str,
    points: u32,
    goals_for: i32,
    goals_against: i32,
}

impl Team {
    fn goal_diff(&self) -> i32 {
        self.goals_for - self.goals_against
    }
}

fn main() {
    let mut teams = vec![
        Team { name: "Arrows", points: 7, goals_for: 4, goals_against: 2 },
        Team { name: "Cobras", points: 7, goals_for: 4, goals_against: 2 },
        Team { name: "Dynamos", points: 1, goals_for: 0, goals_against: 6 },
        Team { name: "Bears", points: 7, goals_for: 4, goals_against: 2 },
    ];

    teams.sort_by_key(|t| (Reverse(t.points), Reverse(t.goal_diff()), Reverse(t.goals_for), t.name));
    teams.reverse();

    for (idx, team) in teams.iter().enumerate() {
        println!(
            "{}. {} - {} pts, GD {:+}, GS {}",
            idx + 1,
            team.name,
            team.points,
            team.goal_diff(),
            team.goals_for
        );
    }
}

use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum State {
    New,
    InProgress,
    Blocked,
    Closed,
}

enum Event {
    Open(&'static str),
    Work(&'static str),
    Block(&'static str),
    Unblock(&'static str),
    Close(&'static str),
    Reopen(&'static str),
}

fn apply(state: Option<State>, event: &Event) -> Option<State> {
    use Event::*;
    use State::*;

    match (state, event) {
        (_, Open(_)) => Some(New),
        (Some(New | Blocked), Work(_)) => Some(InProgress),
        (Some(New | InProgress), Block(_)) => Some(Blocked),
        (Some(Blocked), Unblock(_)) => Some(New),
        (Some(_), Close(_)) => Some(Closed),
        (Some(Closed), Reopen(_)) => Some(Closed),
        (None, Reopen(_)) => Some(InProgress),
        (s, _) => s,
    }
}

fn main() {
    use Event::*;

    let events = vec![
        Open("A"),
        Work("A"),
        Close("A"),
        Reopen("A"),
        Work("A"),
        Open("B"),
        Block("B"),
        Unblock("B"),
        Block("B"),
        Close("B"),
        Open("C"),
        Open("C"),
        Work("C"),
    ];

    let mut tickets: BTreeMap<&str, State> = BTreeMap::new();

    for event in &events {
        let id = match event {
            Open(id) | Work(id) | Block(id) | Unblock(id) | Close(id) | Reopen(id) => *id,
        };
        let next = apply(tickets.get(id).copied(), event);
        if let Some(state) = next {
            tickets.insert(id, state);
        }
    }

    for (id, state) in tickets {
        println!("{}: {:?}", id, state);
    }
}

