use std::collections::BTreeMap;

#[derive(Clone, Debug)]
struct Booking {
    room: &'static str,
    start: u32,
    end: u32,
}

fn fmt_time(minutes: u32) -> String {
    format!("{:02}:{:02}", minutes / 60, minutes % 60)
}

fn fmt_booking(b: &Booking) -> String {
    format!("{} @ {}-{}", b.room, fmt_time(b.start), fmt_time(b.end))
}

fn classify_conflict(existing: &Booking, candidate: &Booking) -> Option<&'static str> {
    if existing.room != candidate.room {
        return None;
    }
    if candidate.start >= existing.end || candidate.end <= existing.start {
        return None;
    }
    if candidate.start > existing.start && candidate.end < existing.end {
        return Some("contained by");
    }
    Some("overlaps")
}

fn process(bookings: &[Booking]) -> String {
    let mut accepted: BTreeMap<&str, Vec<Booking>> = BTreeMap::new();
    let mut accepted_lines = Vec::new();
    let mut rejected_lines = Vec::new();

    for booking in bookings {
        let room_entries = accepted.entry(booking.room).or_default();
        let mut conflict = None;
        for existing in room_entries.iter() {
            if let Some(kind) = classify_conflict(existing, booking) {
                conflict = Some(format!(
                    "{} {} {}",
                    fmt_booking(booking),
                    kind,
                    fmt_booking(existing)
                ));
                break;
            }
        }

        if let Some(line) = conflict {
            rejected_lines.push(line);
        } else {
            room_entries.push(booking.clone());
            accepted_lines.push(fmt_booking(booking));
        }
    }

    format!(
        "accepted:\n{}\n\nrejected:\n{}",
        accepted_lines.join("\n"),
        rejected_lines.join("\n")
    )
}

fn main() {
    let bookings = vec![
        Booking { room: "A1", start: 9 * 60, end: 10 * 60 },
        Booking { room: "A1", start: 10 * 60, end: 11 * 60 },
        Booking { room: "A1", start: 9 * 60 + 30, end: 9 * 60 + 45 },
        Booking { room: "A1", start: 10 * 60, end: 10 * 60 + 30 },
        Booking { room: "A1", start: 11 * 60 + 15, end: 12 * 60 },
        Booking { room: "B2", start: 9 * 60 + 30, end: 10 * 60 + 30 },
        Booking { room: "B2", start: 10 * 60 + 15, end: 10 * 60 + 45 },
        Booking { room: "B2", start: 10 * 60 + 30, end: 11 * 60 },
    ];

    println!("{}", process(&bookings));
}

