use std::collections::BTreeMap;

struct Order {
    region: &'static str,
    amount: u32,
    shipped: bool,
    canceled: bool,
}

#[derive(Default)]
struct Summary {
    orders: u32,
    shipped: u32,
    revenue: u32,
    pending_revenue: u32,
}

fn main() {
    let orders = vec![
        Order { region: "North", amount: 12, shipped: true, canceled: false },
        Order { region: "South", amount: 7, shipped: true, canceled: false },
        Order { region: "North", amount: 5, shipped: false, canceled: false },
        Order { region: "West", amount: 9, shipped: true, canceled: false },
        Order { region: "South", amount: 4, shipped: false, canceled: false },
        Order { region: "South", amount: 3, shipped: false, canceled: true },
    ];

    let mut by_region: BTreeMap<&str, Summary> = BTreeMap::new();
    let mut total = Summary::default();

    for order in orders {
        if order.canceled {
            continue;
        }

        let entry = by_region.entry(order.region).or_default();
        entry.orders += 1;
        total.orders += 1;

        if order.shipped {
            entry.shipped += 1;
            total.shipped += 1;
            entry.revenue += order.amount;
            total.revenue += order.amount;
        } else {
            entry.revenue += order.amount;
            total.revenue += order.amount;
        }
    }

    let mut lines = Vec::new();
    for (region, summary) in by_region {
        lines.push(format!(
            "{}: orders={} shipped={} revenue={} pending_revenue={}",
            region, summary.orders, summary.shipped, summary.revenue, summary.pending_revenue
        ));
    }
    lines.push(format!(
        "TOTAL: orders={} shipped={} revenue={} pending_revenue={}",
        total.orders, total.shipped, total.revenue, total.pending_revenue
    ));

    print!("{}", lines.join("\n"));
}

