#[derive(Clone, Copy)]
struct Booking {
    name: &'static str,
    start: u32,
    end: u32,
}

fn fmt_time(m: u32) -> String {
    format!("{:02}:{:02}", m / 60, m % 60)
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn relation(new_booking: &Booking, existing: &Booking) -> &'static str {
    if new_booking.start <= existing.start && new_booking.end >= existing.end {
        "contains"
    } else {
        "overlaps"
    }
}

fn main() {
    let requests = vec![
        Booking { name: "A", start: 9 * 60, end: 10 * 60 },
        Booking { name: "B", start: 10 * 60, end: 11 * 60 + 30 },
        Booking { name: "C", start: 9 * 60 + 45, end: 10 * 60 + 15 },
        Booking { name: "D", start: 8 * 60 + 30, end: 9 * 60 },
        Booking { name: "E", start: 8 * 60 + 45, end: 10 * 60 + 15 },
        Booking { name: "F", start: 11 * 60 + 30, end: 12 * 60 },
        Booking { name: "G", start: 8 * 60 + 50, end: 9 * 60 + 5 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut rejected: Vec<String> = Vec::new();

    for req in requests {
        let mut conflict = None;
        for existing in &accepted {
            if overlaps(&req, existing) {
                conflict = Some(format!("{} {} {}", req.name, relation(&req, existing), existing.name));
                break;
            }
        }

        if let Some(msg) = conflict {
            rejected.push(msg);
        } else {
            accepted.push(req);
        }
    }

    println!("accepted:");
    for b in &accepted {
        println!("{} {}-{}", b.name, fmt_time(b.start), fmt_time(b.end));
    }
    println!("rejected:");
    for line in &rejected {
        println!("{}", line);
    }
}

