use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    New,
    Active,
    Blocked,
    Done,
    Aborted,
}

#[derive(Clone, Copy)]
struct Task {
    status: Status,
    done_count: u32,
    blocked_count: u32,
    aborted_count: u32,
}

impl Default for Task {
    fn default() -> Self {
        Self {
            status: Status::New,
            done_count: 0,
            blocked_count: 0,
            aborted_count: 0,
        }
    }
}

fn apply(task: &mut Task, event: &str) {
    match event {
        "start" => task.status = Status::Active,
        "block" => {
            task.status = Status::Blocked;
            task.blocked_count += 1;
        }
        "unblock" => task.status = Status::New,
        "finish" => {
            task.status = Status::Done;
            task.done_count += 1;
        }
        "abort" => {
            task.status = Status::Aborted;
            task.aborted_count += 1;
        }
        _ => {}
    }
}

fn status_name(status: Status) -> &'static str {
    match status {
        Status::New => "new",
        Status::Active => "active",
        Status::Blocked => "blocked",
        Status::Done => "done",
        Status::Aborted => "aborted",
    }
}

fn main() {
    let events = [
        ("alpha", "start"),
        ("alpha", "finish"),
        ("alpha", "start"),
        ("beta", "start"),
        ("beta", "block"),
        ("gamma", "start"),
        ("gamma", "finish"),
        ("gamma", "start"),
        ("gamma", "abort"),
        ("gamma", "start"),
        ("gamma", "finish"),
    ];

    let mut tasks: BTreeMap<&str, Task> = BTreeMap::new();
    for (name, event) in events {
        let task = tasks.entry(name).or_default();
        apply(task, event);
    }

    let mut lines = Vec::new();
    for (name, task) in tasks {
        lines.push(format!(
            "{}: {} (done={} blocked={} aborted={})",
            name,
            status_name(task.status),
            task.done_count,
            task.blocked_count,
            task.aborted_count
        ));
    }

    print!("{}", lines.join("\n"));
}

