use std::fmt;

#[derive(Clone, Copy)]
enum Event {
    Open(u32),
    Start,
    Block,
    Unblock,
    Resolve(u32),
    Close,
    Reopen,
}

#[derive(Clone, Copy)]
enum Status {
    New,
    InProgress,
    Blocked,
    Resolved(u32),
    Closed(u32),
}

impl fmt::Display for Status {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Status::New => write!(f, "New"),
            Status::InProgress => write!(f, "InProgress"),
            Status::Blocked => write!(f, "Blocked"),
            Status::Resolved(id) => write!(f, "Resolved({})", id),
            Status::Closed(id) => write!(f, "Closed({})", id),
        }
    }
}

fn apply(mut status: Option<Status>, event: Event) -> Option<Status> {
    match event {
        Event::Open(_) => Some(Status::New),
        Event::Start => Some(Status::InProgress),
        Event::Block => Some(Status::Blocked),
        Event::Unblock => Some(Status::InProgress),
        Event::Resolve(id) => Some(Status::Resolved(id)),
        Event::Close => match status {
            Some(Status::Resolved(id)) => Some(Status::Closed(id)),
            other => other,
        },
        Event::Reopen => Some(Status::InProgress),
    }
}

fn main() {
    let cases = vec![
        (
            "A",
            vec![Event::Open(1), Event::Start, Event::Resolve(5)],
        ),
        (
            "B",
            vec![
                Event::Open(2),
                Event::Start,
                Event::Resolve(3),
                Event::Close,
                Event::Reopen,
            ],
        ),
        (
            "C",
            vec![
                Event::Open(4),
                Event::Start,
                Event::Block,
                Event::Unblock,
                Event::Resolve(6),
                Event::Close,
            ],
        ),
        (
            "D",
            vec![
                Event::Open(7),
                Event::Start,
                Event::Resolve(8),
                Event::Close,
                Event::Reopen,
                Event::Resolve(9),
            ],
        ),
    ];

    for (name, events) in cases {
        let mut status = None;
        for event in events {
            status = apply(status, event);
        }
        println!("{}:{}", name, status.unwrap());
    }
}

