#[derive(Default)]
struct TeamSummary {
    resolved: u32,
    open: u32,
    hours: u32,
}

fn main() {
    let input = "Ops|closed|5\nOps|open|2\nPlatform|closed|3\nPlatform|open|4\nPlatform|closed|8\nBroken line\nOps|closed|0\nPlatform|closed|x";

    let mut teams: BTreeMap<&str, TeamSummary> = BTreeMap::new();

    for line in input.lines() {
        let mut parts = line.split('|');
        let team = match parts.next() {
            Some(v) => v,
            None => continue,
        };
        let status = match parts.next() {
            Some(v) => v,
            None => continue,
        };
        let hours: u32 = parts.next().unwrap_or("0").parse().unwrap_or(0);

        if hours == 0 {
            continue;
        }

        let entry = teams.entry(team).or_default();
        if status == "open" {
            entry.open += 1;
        } else {
            entry.hours += hours;
        }
    }

    let mut total = TeamSummary::default();
    let mut out = Vec::new();

    for (team, summary) in &teams {
        total.resolved += summary.resolved;
        total.open += summary.open;
        total.hours += summary.hours;
        out.push(format!(
            "{}: resolved={} open={} hours={}",
            team, summary.resolved, summary.open, summary.hours
        ));
    }

    out.push(format!(
        "TOTAL: resolved={} open={} hours={}",
        total.resolved, total.open, total.hours
    ));

    println!("{}", out.join("\n"));
}

