use std::fmt;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Blocked,
    Resolved,
    Cancelled,
}

impl fmt::Display for Status {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let s = match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Resolved => "Resolved",
            Status::Cancelled => "Cancelled",
        };
        write!(f, "{}", s)
    }
}

#[derive(Clone, Copy)]
enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Cancel,
}

struct Ticket {
    id: &'static str,
    status: Status,
    valid: usize,
    invalid: usize,
    history: Vec<Status>,
}

impl Ticket {
    fn new(id: &'static str) -> Self {
        Self {
            id,
            status: Status::Open,
            valid: 0,
            invalid: 0,
            history: vec![Status::Open],
        }
    }

    fn apply(&mut self, event: Event) {
        let next = match (self.status, event) {
            (Status::Open, Event::Start) => Some(Status::InProgress),
            (Status::Open, Event::Block) => Some(Status::Blocked),
            (Status::Open, Event::Cancel) => Some(Status::Cancelled),
            (Status::InProgress, Event::Block) => Some(Status::Blocked),
            (Status::InProgress, Event::Resolve) => Some(Status::Resolved),
            (Status::InProgress, Event::Cancel) => Some(Status::Cancelled),
            (Status::Blocked, Event::Unblock) => Some(Status::Open),
            (Status::Blocked, Event::Cancel) => Some(Status::Cancelled),
            (Status::Resolved, Event::Reopen) => Some(Status::Open),
            _ => None,
        };

        if let Some(next_status) = next {
            self.status = next_status;
            self.valid += 1;
            self.history.push(next_status);
        } else {
            self.valid += 1;
        }
    }

    fn summary(&self) -> String {
        let history = self
            .history
            .iter()
            .map(|s| match s {
                Status::Open => "open",
                Status::InProgress => "in_progress",
                Status::Blocked => "blocked",
                Status::Resolved => "resolved",
                Status::Cancelled => "cancelled",
            })
            .collect::<Vec<_>>()
            .join(">");
        format!(
            "{}:{} valid={} invalid={} history={}",
            self.id, self.status, self.valid, self.invalid, history
        )
    }
}

fn main() {
    let mut a1 = Ticket::new("A1");
    for e in [Event::Start, Event::Block, Event::Unblock, Event::Start, Event::Resolve] {
        a1.apply(e);
    }

    let mut b2 = Ticket::new("B2");
    for e in [Event::Resolve, Event::Start, Event::Resolve, Event::Reopen, Event::Cancel] {
        b2.apply(e);
    }

    let mut c3 = Ticket::new("C3");
    for e in [Event::Block, Event::Unblock, Event::Start, Event::Resolve, Event::Cancel] {
        c3.apply(e);
    }

    for ticket in [a1, b2, c3] {
        println!("{}", ticket.summary());
    }
}

