use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub player: String,
    pub score: u32,
    pub attempts: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedEntry {
    pub rank: usize,
    pub player: String,
    pub score: u32,
    pub attempts: u32,
}

pub fn rank_leaderboard(entries: &[Entry]) -> Vec<RankedEntry> {
    let mut best: HashMap<&str, (u32, u32)> = HashMap::new();

    for e in entries {
        best.entry(&e.player)
            .and_modify(|cur| {
                if e.score >= cur.0 {
                    *cur = (e.score, e.attempts);
                }
            })
            .or_insert((e.score, e.attempts));
    }

    let mut rows: Vec<(String, u32, u32)> = best
        .into_iter()
        .map(|(player, (score, attempts))| (player.to_string(), score, attempts))
        .collect();

    rows.sort_by(|a, b| {
        b.1.cmp(&a.1)
            .then(a.2.cmp(&b.2))
            .then(b.0.cmp(&a.0))
    });

    rows.into_iter()
        .enumerate()
        .map(|(idx, (player, score, attempts))| RankedEntry {
            rank: idx + 1,
            player,
            score,
            attempts,
        })
        .collect()
}

