#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Close,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (_, Event::Close) => Status::Closed,
        (Status::Closed, Event::Reopen) => Status::InProgress,
        _ => status,
    }
}

#[cfg(test)]
mod tests {
    use super::{apply_event, Event, Status};

    #[test]
    fn start_moves_open_to_in_progress() {
        assert_eq!(apply_event(Status::Open, Event::Start), Status::InProgress);
    }

    #[test]
    fn close_only_changes_active_tickets() {
        assert_eq!(apply_event(Status::Open, Event::Close), Status::Closed);
        assert_eq!(apply_event(Status::InProgress, Event::Close), Status::Closed);
        assert_eq!(apply_event(Status::Closed, Event::Close), Status::Closed);
    }

    #[test]
    fn reopen_returns_closed_ticket_to_open() {
        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::Open);
    }

    #[test]
    fn reopen_does_nothing_for_non_closed_tickets() {
        assert_eq!(apply_event(Status::Open, Event::Reopen), Status::Open);
        assert_eq!(apply_event(Status::InProgress, Event::Reopen), Status::InProgress);
    }
}

use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SummaryRow {
    pub department: String,
    pub orders: usize,
    pub units: u32,
    pub gross_cents: u32,
}

pub fn summarize_sales(lines: &[&str]) -> Vec<SummaryRow> {
    let mut by_dept: BTreeMap<String, SummaryRow> = BTreeMap::new();

    for line in lines {
        let parts: Vec<_> = line.split('|').collect();
        if parts.len() != 4 {
            continue;
        }

        let dept = parts[0].trim();
        let units: u32 = parts[1].trim().parse().unwrap_or(0);
        let unit_price: u32 = parts[2].trim().parse().unwrap_or(0);
        let discount: u32 = parts[3].trim().parse().unwrap_or(0);

        let gross = units * unit_price;
        let net = gross - discount;

        let row = by_dept.entry(dept.to_string()).or_insert(SummaryRow {
            department: dept.to_string(),
            orders: 0,
            units: 0,
            gross_cents: 0,
        });

        row.orders += 1;
        row.units += units;
        row.gross_cents += net;
    }

    by_dept.into_values().collect()
}

