#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Resolved, Event::Reopen) => Status::Open,
        _ => status,
    }
}

#[cfg(test)]
mod tests {
    use super::{apply_event, Event, Status};

    #[test]
    fn workflow_progresses_normally() {
        let s = apply_event(Status::Open, Event::Start);
        let s = apply_event(s, Event::Resolve);
        let s = apply_event(s, Event::Close);
        assert_eq!(s, Status::Closed);
    }

    #[test]
    fn reopen_from_resolved_goes_back_to_open() {
        assert_eq!(apply_event(Status::Resolved, Event::Reopen), Status::Open);
    }

    #[test]
    fn reopen_from_closed_goes_back_to_open() {
        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::Open);
    }

    #[test]
    fn close_requires_resolved() {
        assert_eq!(apply_event(Status::Open, Event::Close), Status::Open);
        assert_eq!(apply_event(Status::InProgress, Event::Close), Status::InProgress);
    }
}

pub fn summarize_tags(tags: &[&str]) -> Vec<String> {
    tags.iter()
        .filter_map(|tag| {
            let t = tag.trim();
            if t.starts_with('#') {
                Some((t[1..].to_ascii_lowercase(), true))
            } else {
                Some((t.to_ascii_lowercase(), false))
            }
        })
        .scan(Vec::<String>::new(), |seen, (name, active)| {
            if seen.contains(&name) {
                Some(None)
            } else {
                seen.push(name.clone());
                let prefix = if active { "tag:" } else { "raw:" };
                Some(Some(format!("{}{}", prefix, name)))
            }
        })
        .flatten()
        .collect()
}

#[cfg(test)]
