#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Login { trusted_device: bool, risk_score: u8 },
    Transfer { amount_cents: u64, international: bool, flagged: bool },
    PasswordReset { has_2fa: bool, requested_by_support: bool },
    ApiKeyUse { scope_write: bool, ip_allowlisted: bool },
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    Allow,
    Review,
    Challenge,
    Deny,
}

pub fn decide_action(event: Event) -> Action {
    match event {
        Event::Login {
            trusted_device,
            risk_score,
        } => {
            if trusted_device {
                Action::Allow
            } else if risk_score >= 80 {
                Action::Review
            } else {
                Action::Challenge
            }
        }
        Event::Transfer {
            amount_cents,
            international,
            flagged,
        } => {
            if amount_cents >= 100_000 {
                Action::Review
            } else if international {
                Action::Review
            } else if flagged {
                Action::Challenge
            } else {
                Action::Allow
            }
        }
        Event::PasswordReset {
            has_2fa,
            requested_by_support,
        } => {
            if requested_by_support {
                Action::Allow
            } else if has_2fa {
                Action::Challenge
            } else {
                Action::Review
            }
        }
        Event::ApiKeyUse {
            scope_write,
            ip_allowlisted,
        } => {
            if scope_write || !ip_allowlisted {
                Action::Review
            } else {
                Action::Allow
            }
        }
    }
}

#[cfg(test)]
