        );
        assert_eq!(
            decide_action(Event::Transfer {
                amount_cents: 120_000,
                international: false,
                flagged: false
            }),
            Action::Review
        );
        assert_eq!(
            decide_action(Event::Transfer {
                amount_cents: 10_000,
                international: true,
                flagged: false
            }),
            Action::Challenge
        );
        assert_eq!(
            decide_action(Event::Transfer {
                amount_cents: 10_000,
                international: false,
