    pub wins: u32,
    pub draws: u32,
    pub points_for: u32,
    pub points_against: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by_key(|p| {
        (
            Reverse(p.wins * 3 + p.draws),
            Reverse(p.points_for as i32 - p.points_against as i32),
            Reverse(p.points_for),
            p.name.clone(),
