pub fn latest_valid_values(entries: &[&str]) -> Vec<(String, i32)> {
    entries
        .iter()
        .filter_map(|line| {
            let mut parts = line.split(':');
            let name = parts.next()?;
            let value = parts.next()?.parse::<i32>().ok()?;
            let status = parts.next()?;
            if status != "ok" || value < 0 {
                return None;
            }
            Some((name.to_string(), value))
        })
        .fold(Vec::new(), |mut acc, item| {
            if !acc.iter().any(|(name, _)| name == &item.0) {
                acc.push(item);
            }
            acc
        })
}

