#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AppConfig {
    pub host: String,
    pub port: u16,
    pub timeout_ms: u64,
    pub retries: u8,
    pub locked: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub timeout_ms: Option<u64>,
    pub retries: Option<u8>,
    pub locked: Option<bool>,
}

pub fn merge_config(defaults: &AppConfig, file: &PartialConfig, env: &PartialConfig) -> AppConfig {
    let locked = file.locked.or(env.locked).unwrap_or(defaults.locked);

    let host = env
        .host
        .clone()
        .or(file.host.clone())
        .unwrap_or_else(|| defaults.host.clone());

    let port = file.port.or(env.port).unwrap_or(defaults.port);
    let timeout_ms = env.timeout_ms.or(file.timeout_ms).unwrap_or(defaults.timeout_ms);
    let retries = env.retries.or(file.retries).unwrap_or(defaults.retries);

    AppConfig {
        host,
        port,
        timeout_ms,
        retries,
        locked,
    }
}

