#[derive(Clone, Debug)]
pub struct Order {
    pub region: &'static str,
    pub status: &'static str,
    pub amount_cents: i64,
}

pub fn build_region_report(orders: &[Order]) -> Vec<String> {
    let mut rows: Vec<(&'static str, usize, i64)> = Vec::new();

    for order in orders {
        if order.status != "completed" {
            continue;
        }

        let mut found = false;
        for row in &mut rows {
            if row.0 == order.region {
                row.1 += 1;
                row.2 += order.amount_cents;
                found = true;
                break;
            }
        }

        if !found {
            rows.push((order.region, 1, order.amount_cents));
        }
    }

    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows.into_iter()
        .map(|(region, count, total)| format!("{}|{}|{}", region, count, total))
        .collect()
}

