    pub draws: u32,
    pub losses: u32,
}

fn points(p: &Player) -> u32 {
    p.wins * 3 + p.draws
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        points(b)
            .cmp(&points(a))
            .then(a.losses.cmp(&b.losses))
            .then(b.wins.cmp(&a.wins))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, p)| format!("{}. {} ({})", i + 1, p.name, points(&p)))
        .collect()
}

