use std::collections::BTreeMap;

pub fn sales_report(input: &str) -> String {
    let mut groups: BTreeMap<String, (u32, u32)> = BTreeMap::new();

    for line in input.lines() {
        let parts: Vec<_> = line.split(',').collect();
        if parts.len() != 3 {
            continue;
        }
        let category = parts[0].trim();
        let qty: u32 = match parts[1].trim().parse() {
            Ok(v) => v,
            Err(_) => continue,
        };
        let price: u32 = match parts[2].trim().parse() {
            Ok(v) => v,
            Err(_) => continue,
        };
        let entry = groups.entry(category.to_string()).or_insert((0, 0));
        entry.0 += qty;
        entry.1 += qty * price;
    }

    let mut rows: Vec<_> = groups.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(&b.0));

    let mut out = Vec::new();
    let mut total_revenue = 0;
    for (category, (qty, revenue)) in rows {
        out.push(format!("{}|{}|{}", category, qty, revenue));
        total_revenue += revenue;
    }
    out.push(format!("TOTAL|{}", total_revenue));
    out.join("\n")
}

