#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Open;
    for event in events {
        status = match (status, *event) {
            (Status::Open, Event::Start) => Status::InProgress,
            (Status::Open, Event::Resolve) => Status::Resolved,
            (Status::InProgress, Event::Resolve) => Status::Resolved,
            (Status::Resolved, Event::Close) => Status::Closed,
            (Status::Closed, Event::Reopen) => Status::Open,
            (current, Event::Reopen) => current,
            (current, _) => current,
        };
    }
    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn close_requires_resolution() {
        assert_eq!(apply_events(&[Event::Close]), Status::Open);
        assert_eq!(apply_events(&[Event::Start, Event::Close]), Status::InProgress);
        assert_eq!(apply_events(&[Event::Start, Event::Resolve, Event::Close]), Status::Closed);
    }

    #[test]
    fn reopen_from_closed_returns_to_in_progress() {
        let events = [Event::Start, Event::Resolve, Event::Close, Event::Reopen];
        assert_eq!(apply_events(&events), Status::InProgress);
    }

    #[test]
    fn reopen_only_changes_closed_items() {
        assert_eq!(apply_events(&[Event::Reopen]), Status::Open);
        assert_eq!(apply_events(&[Event::Start, Event::Reopen]), Status::InProgress);
        assert_eq!(apply_events(&[Event::Resolve, Event::Reopen]), Status::Resolved);
    }

    #[test]
    fn can_resolve_directly_from_open() {
        assert_eq!(apply_events(&[Event::Resolve]), Status::Resolved);
    }
}

pub fn collect_labels(items: &[&str]) -> Vec<String> {
    items
        .iter()
        .filter_map(|raw| {
            let trimmed = raw.trim();
            if trimmed.is_empty() || trimmed.starts_with('#') {
                return None;
            }

            let name = trimmed.split_once(':').map(|(_, right)| right).unwrap_or(trimmed);
            let name = name.trim();
            if name.is_empty() {
                return None;
