    #[test]
    fn parses_valid_records_with_trimmed_unique_tags() {
        let input = "id:AB12; qty:7; active:true; tags:red, blue,red\n\
                     id:ZX9; qty:0; active:false; tags:";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                Record {
                    id: "AB12".into(),
                    qty: 7,
                    active: true,
                    tags: vec!["red".into(), "blue".into()],
                },
                Record {
                    id: "ZX9".into(),
                    qty: 0,
                    active: false,
                    tags: vec![],
                }
            ]
        );
    }

    #[test]
    fn rejects_invalid_boolean_value() {
        let err = parse_records("id:A1; qty:3; active:yes; tags:x").unwrap_err();
        assert_eq!(err, "line 1: invalid active");
    }

    #[test]
    fn rejects_missing_colon_field() {
        let err = parse_records("id:A1; qty:3; active:true; tags:x; broken").unwrap_err();
        assert_eq!(err, "line 1: malformed field 'broken'");
    }

    #[test]
    fn rejects_duplicate_id_field() {
        let err = parse_records("id:A1; id:B2; qty:3; active:true; tags:x").unwrap_err();
        assert_eq!(err, "line 1: duplicate id");
    }

    #[test]
    fn rejects_bad_id_format() {
        let err = parse_records("id:ab-1; qty:3; active:true; tags:x").unwrap_err();
        assert_eq!(err, "line 1: invalid id");
    }
}

