#[derive(Clone, Debug)]
pub struct Sale {
    pub dept: &'static str,
    pub rep: &'static str,
    pub amount: i32,
    pub refunded: bool,
}

#[derive(Debug, PartialEq, Eq)]
pub struct DeptReport {
    pub dept: String,
    pub gross: i32,
    pub net: i32,
    pub refunds: usize,
    pub reps: usize,
}

pub fn build_report(sales: &[Sale], min_net: i32) -> Vec<DeptReport> {
    let mut rows: Vec<DeptReport> = Vec::new();

    for sale in sales {
        let mut found = false;
        for row in &mut rows {
            if row.dept == sale.dept {
                row.gross += sale.amount;
                row.net += sale.amount;
                if sale.refunded {
                    row.refunds += 1;
                }
                found = true;
                break;
            }
        }
        if !found {
            rows.push(DeptReport {
                dept: sale.dept.to_string(),
                gross: sale.amount,
                net: sale.amount,
                refunds: if sale.refunded { 1 } else { 0 },
                reps: 1,
            });
        }
    }

    rows.retain(|r| r.net >= min_net);
    rows.sort_by(|a, b| b.net.cmp(&a.net).then(a.dept.cmp(&b.dept)));
    rows
}

