#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Open, Event::Start) => Status::InProgress,
        (Status::Open, Event::Resolve) => Status::Resolved,
        (Status::InProgress, Event::Resolve) => Status::Resolved,
        (Status::Resolved, Event::Close) => Status::Closed,
        (Status::Resolved, Event::Reopen) => Status::Open,
        (Status::Closed, Event::Reopen) => Status::Open,
        _ => status,
    }
}

#[cfg(test)]
mod tests {
    use super::{apply_event, Event, Status};

    #[test]
    fn start_moves_open_to_in_progress() {
        assert_eq!(apply_event(Status::Open, Event::Start), Status::InProgress);
    }

    #[test]
    fn resolve_can_happen_from_open_or_in_progress() {
        assert_eq!(apply_event(Status::Open, Event::Resolve), Status::Resolved);
        assert_eq!(apply_event(Status::InProgress, Event::Resolve), Status::Resolved);
    }

    #[test]
    fn close_only_works_after_resolution() {
        assert_eq!(apply_event(Status::Resolved, Event::Close), Status::Closed);
        assert_eq!(apply_event(Status::Open, Event::Close), Status::Open);
        assert_eq!(apply_event(Status::InProgress, Event::Close), Status::InProgress);
    }

    #[test]
    fn reopen_from_resolved_goes_back_to_in_progress() {
        assert_eq!(apply_event(Status::Resolved, Event::Reopen), Status::InProgress);
    }

    #[test]
    fn reopen_from_closed_goes_to_open() {
        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::Open);
    }

    #[test]
    fn invalid_events_leave_state_unchanged() {
        assert_eq!(apply_event(Status::Closed, Event::Close), Status::Closed);
        assert_eq!(apply_event(Status::Resolved, Event::Start), Status::Resolved);
    }
}

