pub fn route_action(kind: EventKind, sev: Severity, acknowledged: bool) -> &'static str {
    match kind {
        EventKind::Cpu => match sev {
            Severity::Low => "log",
            Severity::Medium => {
                if acknowledged { "log" } else { "notify" }
            }
            Severity::High => {
                if acknowledged { "notify" } else { "page" }
            }
            Severity::Critical => {
                if acknowledged { "page" } else { "page" }
            }
        },
        EventKind::Disk => match sev {
            Severity::Low => "log",
            Severity::Medium => "notify",
            Severity::High => {
                if acknowledged { "notify" } else { "page" }
            }
            Severity::Critical => {
                if acknowledged { "page" } else { "notify" }
            }
        },
        EventKind::Auth => match sev {
            Severity::Low => "log",
            Severity::Medium => "notify",
            Severity::High => {
                if acknowledged { "page" } else { "notify" }
            }
            Severity::Critical => {
                if acknowledged { "page" } else { "page" }
            }
        },
    }
}

