#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub endpoint: String,
    pub retries: u8,
    pub cache_enabled: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub endpoint: Option<String>,
    pub retries: Option<u8>,
    pub cache_enabled: Option<bool>,
}

pub fn merge_config(
    defaults: &Config,
    env: &PartialConfig,
    user: &PartialConfig,
) -> Config {
    Config {
        endpoint: env
            .endpoint
            .clone()
            .or_else(|| user.endpoint.clone())
            .unwrap_or_else(|| defaults.endpoint.clone()),
        retries: user.retries.or(env.retries).unwrap_or(defaults.retries),
        cache_enabled: user.cache_enabled.unwrap_or(
            env.cache_enabled.unwrap_or(defaults.cache_enabled),
        ),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn defaults() -> Config {
        Config {
            endpoint: "https://default.service".to_string(),
            retries: 3,
            cache_enabled: true,
        }
    }

    #[test]
    fn uses_defaults_when_overrides_missing() {
        let env = PartialConfig::default();
        let user = PartialConfig::default();

        let merged = merge_config(&defaults(), &env, &user);
        assert_eq!(merged, defaults());
    }

    #[test]
    fn env_overrides_defaults() {
        let env = PartialConfig {
            endpoint: Some("https://env.service".to_string()),
            retries: Some(5),
            cache_enabled: Some(false),
        };
        let user = PartialConfig::default();

        let merged = merge_config(&defaults(), &env, &user);
        assert_eq!(merged.endpoint, "https://env.service");
        assert_eq!(merged.retries, 5);
        assert!(!merged.cache_enabled);
    }

    #[test]
    fn user_overrides_env_for_all_fields() {
        let env = PartialConfig {
            endpoint: Some("https://env.service".to_string()),
            retries: Some(5),
            cache_enabled: Some(true),
        };
        let user = PartialConfig {
            endpoint: Some("https://user.service".to_string()),
