#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub name: String,
    pub count: u32,
    pub active: bool,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();

    for (idx, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut name = None;
        let mut count = None;
        let mut active = None;
        let mut tags = Vec::new();

        for part in line.split(';') {
            let part = part.trim();
            if part.is_empty() {
                continue;
            }
            let (key, value) = part
                .split_once('=')
                .ok_or_else(|| format!("line {} malformed field", idx + 1))?;
            match key.trim() {
                "name" => name = Some(value.trim().to_string()),
                "count" => {
                    count = Some(
                        value
                            .trim()
                            .parse::<u32>()
                            .map_err(|_| format!("line {} invalid count", idx + 1))?,
                    )
                }
                "active" => {
                    active = Some(match value.trim() {
                        "true" => true,
                        "false" => false,
                        _ => return Err(format!("line {} invalid active", idx + 1)),
                    })
                }
                "tags" => {
                    tags = value
                        .split(',')
                        .map(|s| s.trim().to_string())
                        .filter(|s| !s.is_empty())
                        .collect();
                }
                _ => {}
            }
        }

        let rec = Record {
            name: name.ok_or_else(|| format!("line {} missing name", idx + 1))?,
            count: count.ok_or_else(|| format!("line {} missing count", idx + 1))?,
            active: active.ok_or_else(|| format!("line {} missing active", idx + 1))?,
            tags,
        };
        out.push(rec);
    }

    Ok(out)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_valid_records_and_skips_blank_comment_lines() {
        let input = "
# inventory
name=alpha; count=3; active=true; tags=red,blue

name=beta;count=0;active=false;tags=solo
   # ignored comment with leading spaces
name=gamma; count=7; active=true; tags=
";
        let got = parse_records(input).unwrap();
        assert_eq!(
            got,
            vec![
                Record {
                    name: "alpha".into(),
                    count: 3,
                    active: true,
                    tags: vec!["red".into(), "blue".into()],
                },
                Record {
                    name: "beta".into(),
                    count: 0,
                    active: false,
                    tags: vec!["solo".into()],
                },
                Record {
                    name: "gamma".into(),
                    count: 7,
                    active: true,
                    tags: vec![],
                },
            ]
        );
    }

    #[test]
    fn rejects_unknown_keys_and_duplicate_tags() {
        let err = parse_records("name=a;count=1;active=true;extra=nope").unwrap_err();
        assert_eq!(err, "line 1 unknown key extra");

        let err = parse_records("name=a;count=1;active=true;tags=x,x").unwrap_err();
        assert_eq!(err, "line 1 duplicate tag x");
    }

    #[test]
    fn validates_name_and_count_rules() {
        let err = parse_records("name= ;count=1;active=true").unwrap_err();
        assert_eq!(err, "line 1 invalid name");

        let err = parse_records("name=ab;count=1;active=true").unwrap_err();
        assert_eq!(err, "line 1 invalid name");

        let err = parse_records("name=ok_name;count=0;active=true").unwrap_err();
        assert_eq!(err, "line 1 count must be positive when active");
    }
}

