#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub score: u32,
    pub solved: u32,
    pub penalty: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: u32,
    pub name: String,
    pub score: u32,
    pub solved: u32,
    pub penalty: u32,
}

pub fn leaderboard(players: &[Player]) -> Vec<RankedPlayer> {
    let mut items = players.to_vec();
    items.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.penalty.cmp(&b.penalty))
            .then_with(|| a.name.cmp(&b.name))
    });

    let mut out = Vec::with_capacity(items.len());
    let mut rank = 1u32;

    for (idx, p) in items.into_iter().enumerate() {
        if idx > 0 {
            let prev = &out[idx - 1];
            if prev.score != p.score || prev.penalty != p.penalty {
                rank += 1;
            }
        }
        out.push(RankedPlayer {
            rank,
            name: p.name,
            score: p.score,
            solved: p.solved,
            penalty: p.penalty,
        });
    }

    out
}

