enum Action {
    Open,
    Close,
    Archive,
}

enum Event {
    User(Action),
    System(Action),
    Replay(u8, Action),
    Ignore,
}

fn weight(event: &Event) -> u32 {
    match event {
        Event::User(Action::Open) => 1,
        Event::User(Action::Close) => 1,
        Event::User(Action::Archive) => 1,
        Event::System(Action::Open) => 2,
        Event::System(Action::Close) => 2,
        Event::System(Action::Archive) => 1,
        Event::Replay(times, Action::Open) => *times as u32,
        Event::Replay(times, Action::Close) => 1,
        Event::Replay(times, Action::Archive) => 1,
        Event::Ignore => 0,
    }
}

fn bucket(event: &Event) -> Option<&'static str> {
    match event {
        Event::User(Action::Open) | Event::System(Action::Open) | Event::Replay(_, Action::Open) => Some("open"),
        Event::User(Action::Close) | Event::System(Action::Close) => Some("close"),
        Event::User(Action::Archive) | Event::System(Action::Archive) | Event::Replay(_, Action::Archive) => Some("archive"),
        Event::Replay(_, Action::Close) => None,
        Event::Ignore => None,
    }
}

fn main() {
    let events = [
        Event::User(Action::Open),
        Event::System(Action::Open),
        Event::Replay(3, Action::Open),
        Event::User(Action::Close),
        Event::System(Action::Close),
        Event::Replay(2, Action::Close),
        Event::System(Action::Archive),
        Event::Replay(1, Action::Archive),
        Event::Ignore,
    ];

    let mut open = 0;
    let mut close = 0;
    let mut archive = 0;

    for event in &events {
        match bucket(event) {
            Some("open") => open += weight(event),
            Some("close") => close += weight(event),
            Some("archive") => archive += weight(event),
            _ => {}
        }
    }

    let total = open + close + archive;
    println!("open {}", open);
    println!("close {}", close);
    println!("archive {}", archive);
    println!("total {}", total);
}

