fn parse_line(line: &str) -> Result<(String, u32, u32), String> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() < 3 {
        return Err("expected 3 fields".to_string());
    }

    let id = parts[0].trim().to_string();
    if id.len() < 2 || !id.chars().all(|c| c.is_ascii_alphanumeric()) {
        return Err("invalid id".to_string());
    }

    let qty: u32 = parts[1].trim().parse().map_err(|_| "invalid qty".to_string())?;
    if qty == 0 || qty > 10 {
        return Err("qty out of range".to_string());
    }

    let cents: u32 = parts[2].trim().parse().map_err(|_| "invalid cents".to_string())?;
    if cents == 0 {
        return Err("invalid cents".to_string());
    }

    Ok((id, qty, cents))
}

fn main() {
    let input = "A12|3|499\na-1|2|150\nB77|0|200\nC99|4|0\nA12|7\nA12|1|100\nD07|10|250";
    let mut seen: Vec<String> = Vec::new();
    let mut valid = 0u32;
    let mut invalid = 0u32;
    let mut total_cents = 0u32;
    let mut out = Vec::new();

    for (idx, line) in input.lines().enumerate() {
        match parse_line(line) {
            Ok((id, qty, cents)) => {
                if seen.contains(&id) {
                    invalid += 1;
                    out.push(format!("drop line {}: duplicate id", idx + 1));
                } else {
                    seen.push(id.clone());
                    valid += 1;
                    total_cents += qty * cents;
                    out.push(format!("ok: {} x{} @ {}", id, qty, cents));
                }
            }
            Err(msg) => {
                invalid += 1;
                out.push(format!("drop line {}: {}", idx + 1, msg));
            }
        }
    }

    out.push(format!("valid={} invalid={} total_cents={}", valid, invalid, total_cents));
    print!("{}", out.join("\n"));
}

