const INPUT: &str = "A12,blue,7\nB9,green,5\nC77,red,x\nD55,green,0\nE42,yellow,3\nF66,blue,12,extra\n";

fn valid_id(s: &str) -> bool {
    let bytes = s.as_bytes();
    if bytes.len() != 3 {
        return false;
    }
    bytes[0].is_ascii_uppercase() && bytes[1].is_ascii_digit()
}

fn valid_color(s: &str) -> bool {
    matches!(s, "red" | "green")
}

fn main() {
    let mut ok_count = 0;
    let mut err_count = 0;
    let mut qty_sum = 0;
    let mut out = Vec::new();

    for line in INPUT.lines() {
        let parts: Vec<&str> = line.split(',').collect();
        if parts.len() < 3 {
            err_count += 1;
            out.push(format!("err: {} | wrong field count", line));
            continue;
        }

        let id = parts[0];
        let color = parts[1];
        let qty_raw = parts[2];
        let mut reasons = Vec::new();

        if !valid_id(id) {
            reasons.push("bad id");
        }
        if !valid_color(color) {
            reasons.push("bad color");
        }
        match qty_raw.parse::<u32>() {
            Ok(n) if n > 0 && n < 10 => qty_sum += n,
            Ok(_) => reasons.push("qty out of range"),
            Err(_) => reasons.push("bad qty"),
        }

        if reasons.is_empty() {
            ok_count += 1;
            out.push(format!("ok: {} {} {}", id, color, qty_raw));
        } else {
            err_count += 1;
            out.push(format!("err: {} | {}", line, reasons.join(", ")));
        }
    }

    out.push(format!("ok_count={} err_count={} qty_sum={}", ok_count, err_count, qty_sum));
    println!("{}", out.join("\n"));
}

