use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Priority {
    Low,
    Normal,
    High,
}

enum Action<'a> {
    Open { owner: &'a str, priority: Priority },
    Close { owner: &'a str },
    Reopen { owner: &'a str, priority: Priority },
    Escalate { owner: &'a str },
}

#[derive(Default)]
struct Stats {
    open: usize,
    closed: usize,
    flagged: usize,
    owner_closed: BTreeMap<String, usize>,
    high_open: usize,
}

fn apply(stats: &mut Stats, action: &Action<'_>) {
    match action {
        Action::Open { owner: _, priority } => {
            stats.open += 1;
            if matches!(priority, Priority::High) {
                stats.high_open += 1;
            }
        }
        Action::Close { owner } => {
            stats.closed += 1;
            *stats.owner_closed.entry((*owner).to_string()).or_default() += 1;
        }
        Action::Reopen { owner, priority } => {
            stats.closed += 1;
            *stats.owner_closed.entry((*owner).to_string()).or_default() += 1;
            if matches!(priority, Priority::High) {
                stats.high_open += 1;
            }
        }
        Action::Escalate { owner: _ } => {
            stats.open += 1;
        }
    }
}

fn render(stats: &Stats) -> String {
    let mut lines = vec![
        format!("open:{}", stats.open),
        format!("closed:{}", stats.closed),
        format!("flagged:{}", stats.flagged),
    ];
    for (owner, count) in &stats.owner_closed {
        lines.push(format!("owner:{}={}", owner, count));
    }
    lines.push(format!("high_open:{}", stats.high_open));
    lines.join("\n")
}

fn main() {
    let actions = [
        Action::Open {
            owner: "ann",
            priority: Priority::High,
        },
        Action::Escalate { owner: "ann" },
        Action::Close { owner: "ann" },
        Action::Open {
            owner: "bob",
            priority: Priority::Low,
        },
        Action::Reopen {
            owner: "zoe",
            priority: Priority::Normal,
        },
        Action::Close { owner: "zoe" },
    ];

    let mut stats = Stats::default();
    for action in &actions {
        apply(&mut stats, action);
    }
    print!("{}", render(&stats));
}

