use std::fmt::Write;

#[derive(Clone, Debug)]
struct Config {
    mode: Option<&'static str>,
    retries: Option<u32>,
    timeout: Option<u32>,
    endpoint: Option<&'static str>,
    tags: Vec<&'static str>,
}

fn merge(base: &Config, env: &Config, cli: &Config) -> Config {
    Config {
        mode: base.mode.or(env.mode).or(cli.mode),
        retries: base.retries.or(env.retries).or(cli.retries),
        timeout: base.timeout.or(env.timeout).or(cli.timeout),
        endpoint: base.endpoint.or(env.endpoint).or(cli.endpoint),
        tags: {
            let mut tags = Vec::new();
            tags.extend(cli.tags.iter().copied());
            tags.extend(env.tags.iter().copied());
            tags.extend(base.tags.iter().copied());
            tags
        },
    }
}

fn render(cfg: &Config) -> String {
    let mut out = String::new();
    writeln!(&mut out, "mode={}", cfg.mode.unwrap_or("unknown")).unwrap();
    writeln!(&mut out, "retries={}", cfg.retries.unwrap_or(0)).unwrap();
    writeln!(&mut out, "timeout={}", cfg.timeout.unwrap_or(0)).unwrap();
    writeln!(&mut out, "endpoint={}", cfg.endpoint.unwrap_or("none")).unwrap();
    write!(&mut out, "tags={}", cfg.tags.join(",")).unwrap();
    out
}

fn main() {
    let defaults = Config {
        mode: Some("safe"),
        retries: Some(3),
