}

fn can_book(existing: &[(u32, u32)], candidate: (u32, u32)) -> bool {
    existing.iter().all(|&slot| !overlaps(slot, candidate))
}

fn fmt(slot: (u32, u32)) -> String {
    format!("{:02}:{:02}-{:02}:{:02}", slot.0 / 60, slot.0 % 60, slot.1 / 60, slot.1 % 60)
}

