fn action(req: &Request) -> &'static str {
    match (&req.method, req.path) {
        (Method::Get, _) => "cache-hit",
        (Method::Head, "/status") => "meta",
        (Method::Post, "/submit") => "create",
        (Method::Delete, path) if path.starts_with("/post/") => "remove",
        (_, path) if path.starts_with("/admin") => "cache-hit",
