    verbose: bool,
}

#[derive(Clone, Copy)]
struct PartialConfig {
    timeout: Option<u32>,
    retries: Option<u32>,
    verbose: Option<bool>,
}

fn merge(base: Config, file: PartialConfig, env: PartialConfig, cli: PartialConfig) -> Config {
    let timeout = file.timeout.or(env.timeout).or(cli.timeout).unwrap_or(base.timeout);
    let retries = file.retries.or(env.retries).or(cli.retries).unwrap_or(base.retries);
    let verbose = cli.verbose.unwrap_or(env.verbose.unwrap_or(file.verbose.unwrap_or(base.verbose)));

    Config {
        timeout,
        retries,
        verbose,
    }
}

