use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Event {
    Create(&'static str),
    Close(&'static str),
    Reopen(&'static str),
}

#[derive(Clone, Copy)]
enum Status {
    Open,
    Closed,
}

fn apply(events: &[Event]) -> BTreeMap<&'static str, Status> {
    let mut tickets = BTreeMap::new();
    for event in events {
        match *event {
            Event::Create(id) => {
                tickets.insert(id, Status::Open);
            }
            Event::Close(id) => {
                if tickets.contains_key(id) {
                    tickets.insert(id, Status::Closed);
                }
            }
            Event::Reopen(id) => {
                if tickets.contains_key(id) {
                    tickets.insert(id, Status::Open);
                }
            }
        }
    }
    tickets
}

fn label(status: Status) -> &'static str {
    match status {
        Status::Open => "Open",
        Status::Closed => "Closed",
    }
}

fn main() {
    let events = [
        Event::Create("A"),
        Event::Close("A"),
        Event::Reopen("A"),
        Event::Close("A"),
        Event::Close("B"),
        Event::Create("B"),
        Event::Close("B"),
        Event::Reopen("C"),
        Event::Create("C"),
    ];

    let tickets = apply(&events);
    for (id, status) in tickets {
        println!("{}:{}", id, label(status));
    }
}

