fn summarize(input: &str) -> String {
    let mut items: Vec<(String, i32)> = input
        .lines()
        .filter_map(|line| {
            let mut parts = line.split(':');
            let name = parts.next()?.trim();
            let value = parts.next()?.trim().parse::<i32>().ok()?;
            if name.is_empty() || value <= 0 {
                return None;
            }
            Some((name.to_string(), value))
        })
        .collect();

    items.sort_by(|a, b| a.0.cmp(&b.0));

    items
        .into_iter()
        .filter(|(_, value)| *value >= 5)
        .map(|(name, value)| format!("{}:{}", name, value))
        .collect::<Vec<_>>()
        .join("\n")
}

fn main() {
    let input = "rust:8
iter:5
skip:4
map:7
rust:10
iter:4
bad:0
junk
";
    println!("{}", summarize(input));
}

