use std::fmt;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum State {
    Open,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

impl fmt::Display for State {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let s = match self {
            State::Open => "Open",
            State::InProgress => "InProgress",
            State::Blocked => "Blocked",
            State::Resolved => "Resolved",
            State::Closed => "Closed",
        };
        f.write_str(s)
    }
}

fn apply_event(state: State, event: &str) -> State {
    match event {
        "start" => State::InProgress,
        "block" => State::Blocked,
        "unblock" => State::Open,
        "resolve" => State::Closed,
        "close" => State::Closed,
        "reopen" => State::Open,
        _ => state,
    }
}

fn main() {
    let cases = [
        ("A", vec!["start", "resolve", "close"]),
        ("B", vec!["start", "block", "unblock", "resolve"]),
        ("C", vec!["start", "resolve", "reopen"]),
        ("D", vec!["start", "block", "close"]),
    ];

    let mut lines = Vec::new();
    for (id, events) in cases {
        let mut state = State::Open;
        for event in events {
            state = apply_event(state, event);
        }
        lines.push(format!("{}:{}", id, state));
    }

    println!("{}", lines.join("\n"));
}

