fn build_report(events: &[Event]) -> String {
    let mut rows: Vec<_> = events
        .iter()
        .filter(|e| e.active)
        .map(|e| {
            let mut tags: Vec<_> = e
                .tags
                .iter()
                .copied()
                .filter(|t| !t.is_empty())
                .collect();
            tags.sort_unstable();
            tags.dedup();
            (e.user, tags)
        })
        .collect();

    rows.sort_unstable_by(|a, b| a.0.cmp(b.0));

    let body = rows
        .into_iter()
        .map(|(user, tags)| format!("{} => {} tags [{}]", user, tags.len(), tags.join(",")))
        .collect::<Vec<_>>()
        .join("\n");

    format!("active recent users\n{}", body)
