    let users = by_user
        .into_iter()
        .map(|(u, n)| format!("{}:{}", u, n))
        .collect::<Vec<_>>()
        .join(",");

    print!(
        "{{\"accepted\":{},\"rejected\":{},\"users\":[{}]}}",
