    if !b.iter().enumerate().all(|(i, c)| matches!(i, 4 | 7 | 10 | 13) || c.is_ascii_digit()) {
        return false;
    }
    let month: u32 = ts[5..7].parse().ok().unwrap_or(0);
    let day: u32 = ts[8..10].parse().ok().unwrap_or(0);
    let hour: u32 = ts[11..13].parse().ok().unwrap_or(99);
    let minute: u32 = ts[14..16].parse().ok().unwrap_or(99);
    (1..=12).contains(&month) && (1..=31).contains(&day) && hour < 24 && minute < 60
}

