use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Clone, Copy, Debug)]
enum Event {
    Create,
    Start,
    Resolve,
    Reopen,
    Close,
}

fn apply(status: Option<Status>, event: Event) -> Option<Status> {
    match event {
        Event::Create => Some(Status::Open),
        Event::Start => Some(Status::InProgress),
        Event::Resolve => Some(Status::Resolved),
        Event::Reopen => Some(Status::Open),
        Event::Close => Some(Status::Closed),
    }
}

fn main() {
    let events = vec![
        ("A", Event::Create),
        ("A", Event::Start),
        ("A", Event::Resolve),
        ("A", Event::Close),
        ("B", Event::Create),
        ("B", Event::Resolve),
        ("B", Event::Close),
        ("B", Event::Reopen),
        ("B", Event::Resolve),
        ("C", Event::Create),
        ("C", Event::Close),
        ("C", Event::Reopen),
        ("D", Event::Start),
        ("D", Event::Create),
        ("D", Event::Start),
        ("D", Event::Resolve),
        ("D", Event::Close),
    ];

    let mut states: BTreeMap<&str, Status> = BTreeMap::new();
    for (id, event) in events {
        let next = apply(states.get(id).copied(), event);
        if let Some(s) = next {
            states.insert(id, s);
        }
    }

    for (id, status) in states {
        let label = match status {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Resolved => "Resolved",
            Status::Closed => "Closed",
        };
        println!("{}:{}", id, label);
    }
}

