    match event {
        Event::Create => match status {
            None => Some(Status::Open),
            Some(current) => Some(current),
        },
        Event::Start => match status {
            Some(Status::Open) => Some(Status::InProgress),
            Some(current) => Some(current),
            None => None,
        },
        Event::Resolve => match status {
            Some(Status::Open) | Some(Status::InProgress) => Some(Status::Resolved),
            Some(current) => Some(current),
            None => None,
        },
        Event::Reopen => Some(Status::Open),
        Event::Close => match status {
            Some(Status::Resolved) => Some(Status::Closed),
            Some(current) => Some(current),
            None => None,
        },
    }
}

Event::Reopen => match status {
    Some(Status::Resolved) | Some(Status::Closed) => Some(Status::Open),
    Some(current) => Some(current),
    None => None,
},

