struct Config {
    host: Option<&'static str>,
    port: Option<u16>,
    debug: Option<bool>,
    tags: Vec<&'static str>,
}

fn merge(defaults: &Config, file: &Config, env: &Config) -> Config {
    let host = defaults.host.or(file.host).or(env.host);
    let port = defaults.port.or(file.port).or(env.port);
    let debug = defaults.debug.or(file.debug).or(env.debug);

    let tags = if !env.tags.is_empty() {
        env.tags.clone()
    } else if !file.tags.is_empty() {
        file.tags.clone()
    } else {
        defaults.tags.clone()
    };

    Config { host, port, debug, tags }
}

fn render(cfg: &Config) -> String {
    let tags = cfg
        .tags
        .iter()
        .map(|t| format!("\"{}\"", t))
        .collect::<Vec<_>>()
        .join(",");

    format!(
        "{{\"host\":\"{}\",\"port\":{},\"debug\":{},\"tags\":[{}]}}",
        cfg.host.unwrap_or("localhost"),
        cfg.port.unwrap_or(80),
        cfg.debug.unwrap_or(false),
        tags
    )
}

