#[derive(Clone, Copy)]
struct Booking {
    id: &'static str,
    start: u32,
    end: u32,
}

fn overlaps(a: &Booking, b: &Booking) -> bool {
    let starts_inside = a.start >= b.start && a.start <= b.end;
    let ends_inside = a.end >= b.start && a.end <= b.end;
    starts_inside || ends_inside
}

fn main() {
    let requests = [
        Booking { id: "A", start: 60, end: 120 },
        Booking { id: "B", start: 120, end: 150 },
        Booking { id: "C", start: 150, end: 180 },
        Booking { id: "D", start: 170, end: 175 },
        Booking { id: "E", start: 180, end: 210 },
        Booking { id: "F", start: 30, end: 60 },
        Booking { id: "G", start: 80, end: 90 },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut conflicts: Vec<String> = Vec::new();

    for req in requests {
        if let Some(existing) = accepted.iter().find(|b| overlaps(&req, b)) {
            conflicts.push(format!("{}->{}", req.id, existing.id));
        } else {
            accepted.push(req);
        }
    }

    let accepted_ids = accepted.iter().map(|b| b.id).collect::<Vec<_>>().join(",");
    let conflict_ids = conflicts.join(",");

    println!("accepted: {}", accepted_ids);
    println!("conflicts: {}", conflict_ids);
}

