fn parse_line(line: &str) -> Option<(String, u32)> {
    let mut user = None;
    let mut action = None;
    let mut duration = None;

    for part in line.split('|') {
        let (key, value) = part.split_once('=')?;
        match key {
            "user" => user = Some(value.to_string()),
            "action" => action = Some(value.to_string()),
            "duration_ms" => duration = value.parse::<u32>().ok(),
            _ => {}
        }
    }

    let user = user?;
    let action = action?;
    let duration = duration?;

    if action != "login" && action != "logout" {
        return None;
    }

    Some((user, duration))
}

fn main() {
    let input = [
        "user=alice|action=login|duration_ms=12",
        "user=bob|action=upload|duration_ms=5",
        "user=alice|action=logout|duration_ms=28",
        "action=login|duration_ms=9",
        "user=claire|action=login|duration_ms=-4",
        "user=dave|action=login|duration_ms=7|duration_ms=8",
    ];

    let mut valid = 0usize;
    let mut invalid = 0usize;
    let mut users: Vec<String> = Vec::new();
    let mut total_ms = 0u32;

    for line in input {
        if let Some((user, ms)) = parse_line(line) {
            valid += 1;
            total_ms += ms;
            if !users.contains(&user) {
                users.push(user);
            }
        } else {
            invalid += 1;
        }
    }

    users.sort();
    println!(
        "valid={} invalid={} users={} total_ms={}",
        valid,
        invalid,
        users.join(","),
        total_ms
    );
}

