#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Login { success: bool, admin: bool },
    Purchase { cents: u32, refunded: bool },
    Timeout { retries: u8 },
    Audit,
}

pub fn score_event(event: Event) -> i32 {
    match event {
        Event::Login {
            success: true,
            admin: true,
        } => 10,
        Event::Login {
            success: true,
            admin: false,
        } => 5,
        Event::Login { success: false, .. } => -4,
        Event::Purchase {
            refunded: true, ..
        } => -3,
        Event::Purchase { cents, .. } if cents >= 5_000 => 8,
        Event::Purchase { cents, .. } if cents >= 500 => 2,
        Event::Purchase { .. } => 1,
        Event::Timeout { retries: 0 } => 0,
        Event::Timeout { retries: 1..=3 } => -1,
        Event::Timeout { retries } if retries >= 4 => -5,
        Event::Audit => 3,
    }
}

pub fn summarize(events: &[Event]) -> String {
    let total: i32 = events.iter().copied().map(score_event).sum();
    let severity = if total >= 12 {
        "high"
    } else if total >= 4 {
        "medium"
    } else {
        "low"
    };

    format!("total={total};severity={severity}")
}

#[cfg(test)]
mod tests {
    use super::{score_event, summarize, Event};

    #[test]
    fn login_branches_are_distinct() {
        assert_eq!(score_event(Event::Login { success: true, admin: true }), 10);
        assert_eq!(score_event(Event::Login { success: true, admin: false }), 5);
        assert_eq!(score_event(Event::Login { success: false, admin: true }), -4);
    }

    #[test]
    fn purchase_branches_respect_refund_and_thresholds() {
        assert_eq!(score_event(Event::Purchase { cents: 10_000, refunded: true }), -3);
        assert_eq!(score_event(Event::Purchase { cents: 5_000, refunded: false }), 8);
        assert_eq!(score_event(Event::Purchase { cents: 700, refunded: false }), 2);
        assert_eq!(score_event(Event::Purchase { cents: 100, refunded: false }), 1);
    }

    #[test]
    fn timeout_ranges_and_audit_are_handled() {
        assert_eq!(score_event(Event::Timeout { retries: 0 }), 0);
        assert_eq!(score_event(Event::Timeout { retries: 2 }), -1);
        assert_eq!(score_event(Event::Timeout { retries: 4 }), -5);
        assert_eq!(score_event(Event::Audit), 3);
    }

    #[test]
    fn summary_uses_total_score_thresholds() {
        let low = [Event::Timeout { retries: 2 }, Event::Purchase { cents: 100, refunded: false }];
        let medium = [Event::Audit, Event::Purchase { cents: 700, refunded: false }];
        let high = [
            Event::Login { success: true, admin: true },
            Event::Purchase { cents: 5_000, refunded: false },
            Event::Timeout { retries: 0 },
        ];

        assert_eq!(summarize(&low), "total=0;severity=low");
        assert_eq!(summarize(&medium), "total=5;severity=medium");
        assert_eq!(summarize(&high), "total=18;severity=high");
    }
}

pub fn overlaps(a: (u32, u32), b: (u32, u32)) -> bool {
    let (a_start, a_end) = a;
    let (b_start, b_end) = b;
    assert!(a_start < a_end, "start must be before end");
    assert!(b_start < b_end, "start must be before end");
    a_start < b_end && b_start < a_end
}

pub fn can_book(existing: &[(u32, u32)], requested: (u32, u32)) -> bool {
    existing.iter().all(|&slot| !overlaps(slot, requested))
}

#[cfg(test)]
mod tests {
    use super::{can_book, overlaps};

    #[test]
    fn touching_edges_do_not_overlap() {
        assert!(!overlaps((10, 20), (20, 30)));
        assert!(!overlaps((20, 30), (10, 20)));
    }

    #[test]
    fn partial_and_full_overlap_are_detected() {
        assert!(overlaps((10, 20), (15, 25)));
        assert!(overlaps((10, 20), (10, 20)));
        assert!(overlaps((10, 20), (12, 18)));
    }

    #[test]
    fn can_book_when_request_fits_between_existing_slots() {
        let existing = vec![(9, 10), (12, 14), (18, 21)];
        assert!(can_book(&existing, (10, 12)));
        assert!(can_book(&existing, (14, 18)));
    }

    #[test]
    fn rejects_conflicts_against_any_existing_slot() {
        let existing = vec![(9, 11), (13, 16), (20, 24)];
        assert!(!can_book(&existing, (10, 12)));
        assert!(!can_book(&existing, (15, 21)));
        assert!(!can_book(&existing, (8, 25)));
    }

    #[test]
    #[should_panic(expected = "start must be before end")]
    fn invalid_requested_interval_panics() {
        let _ = can_book(&[], (5, 5));
    }
}

