        Event::Block("A"),
        Event::Unblock("A"),
        Event::Finish("A"),
        Event::Start("B"),
        Event::Finish("B"),
        Event::Block("C"),
        Event::Add("D"),
        Event::Start("D"),
        Event::Finish("A"),
        Event::Start("C"),
    ];

    let mut items: BTreeMap<&str, Status> = BTreeMap::new();

    for event in events {
        match event {
            Event::Add(id) => {
                items.entry(id).or_insert(Status::Ready);
            }
            Event::Start(id) => {
                if matches!(items.get(id), Some(Status::Ready)) {
                    items.insert(id, Status::Running);
                }
            }
            Event::Block(id) => {
                if matches!(items.get(id), Some(Status::Running)) {
                    items.insert(id, Status::Blocked);
                }
            }
            Event::Unblock(id) => {
                if matches!(items.get(id), Some(Status::Blocked)) {
                    items.insert(id, Status::Ready);
                }
            }
            Event::Finish(id) => {
                if matches!(items.get(id), Some(Status::Running)) {
                    items.insert(id, Status::Done);
                }
            }
        }
    }

    let mut ready = 0;
    let mut running = 0;
    let mut blocked = 0;
    let mut done = 0;

    for status in items.values() {
        match status {
            Status::Ready => ready += 1,
            Status::Running => running += 1,
            Status::Blocked => blocked += 1,
            Status::Done => done += 1,
        }
    }

    println!("ready={} running={} done={} blocked={}", ready, running, done, blocked);

    for (id, status) in items {
        let name = match status {
            Status::Ready => "Ready",
            Status::Running => "Running",
            Status::Blocked => "Blocked",
            Status::Done => "Done",
        };
        println!("{}:{}", id, name);
    }
}

enum Alert {
    Ok(&'static str),
    Warn { code: u8, msg: &'static str },
    Error(&'static str),
    Skip(Option<&'static str>),
}

fn render(alert: &Alert) -> String {
    match alert {
        Alert::Ok(msg) => format!("ok: {}", msg),
        Alert::Warn { code, msg } if *code >= 10 => format!("warn: [{}] {}", code, msg),
        Alert::Warn { .. } => String::from("warn: retrying"),
        Alert::Error(msg) => format!("err: {}", msg),
        Alert::Skip(Some(reason)) => format!("skip: {}", reason),
        Alert::Skip(None) => String::from("skip: no reason"),
    }
}

fn main() {
    let alerts = [
        Alert::Ok("boot"),
        Alert::Warn { code: 10, msg: "cache stale" },
        Alert::Error("disk full"),
        Alert::Skip(Some("disabled by flag")),
        Alert::Warn { code: 3, msg: "network jitter" },
    ];

    let mut ok = 0;
    let mut warn = 0;
    let mut err = 0;
    let mut skip = 0;
    let mut lines = Vec::new();

    for alert in &alerts {
        match alert {
            Alert::Ok(_) => ok += 1,
            Alert::Warn { .. } => warn += 1,
            Alert::Error(_) => err += 1,
            Alert::Skip(_) => skip += 1,
        }
        lines.push(render(alert));
    }

    lines.push(format!(
        "summary ok={} warn={} err={} skip={}",
        ok, warn, err, skip
    ));

    print!("{}", lines.join("\n"));
}

fn main() {
    let mut rows = vec![
        ("Rome", 15),
        ("Oslo", 17),
        ("Kyoto", 12),
        ("Lima", 17),
        ("Bern", 15),
    ];

    rows.sort_by(|a, b| {
        b.1.cmp(&a.1)
            .then_with(|| b.0.cmp(&a.0))
    });

    let out = rows
        .iter()
        .enumerate()
        .map(|(i, (name, score))| format!("{}. {} - {}", i + 1, name, score))
        .collect::<Vec<_>>()
        .join("\n");

    print!("{}", out);
}
